const input = $input.first().json;
const coin = (input.coin || 'bitcoin').toLowerCase().trim();
const currency = (input.currency || 'eur').toLowerCase().trim();

try {
  // First try direct ID lookup
  const data = await helpers.httpRequest({
    method: 'GET',
    url: 'https://api.coingecko.com/api/v3/simple/price?ids=' + encodeURIComponent(coin) + '&vs_currencies=' + currency + '&include_24hr_change=true&include_market_cap=true&include_24hr_vol=true'
  });

  if (!data[coin]) {
    // Try search to find the coin ID
    const search = await helpers.httpRequest({
      method: 'GET',
      url: 'https://api.coingecko.com/api/v3/search?query=' + encodeURIComponent(coin)
    });

    if (!search.coins || search.coins.length === 0) {
      return [{ json: { error: 'Cryptocurrency "' + coin + '" not found. Try the full name (e.g. bitcoin, ethereum, solana).' } }];
    }

    const coinId = search.coins[0].id;
    const coinName = search.coins[0].name;
    const coinSymbol = search.coins[0].symbol;

    const data2 = await helpers.httpRequest({
      method: 'GET',
      url: 'https://api.coingecko.com/api/v3/simple/price?ids=' + coinId + '&vs_currencies=' + currency + '&include_24hr_change=true&include_market_cap=true&include_24hr_vol=true'
    });

    if (!data2[coinId]) {
      return [{ json: { error: 'Could not fetch price for ' + coinName + '.' } }];
    }

    const p = data2[coinId];
    const cur = currency.toUpperCase();
    const change = p[currency + '_24h_change'];
    const changeStr = change !== undefined ? (change >= 0 ? '+' : '') + change.toFixed(2) + '%' : 'N/A';
    const mcap = p[currency + '_market_cap'];
    const mcapStr = mcap ? mcap.toLocaleString('en-US') : 'N/A';
    const vol = p[currency + '_24h_vol'];
    const volStr = vol ? vol.toLocaleString('en-US') : 'N/A';

    let result = coinName + ' (' + coinSymbol.toUpperCase() + ')\n';
    result += '  Price: ' + p[currency].toLocaleString('en-US', {minimumFractionDigits: 2, maximumFractionDigits: 8}) + ' ' + cur + '\n';
    result += '  24h Change: ' + changeStr + '\n';
    result += '  Market Cap: ' + mcapStr + ' ' + cur + '\n';
    result += '  24h Volume: ' + volStr + ' ' + cur;
    return [{ json: { result } }];
  }

  const p = data[coin];
  const cur = currency.toUpperCase();
  const change = p[currency + '_24h_change'];
  const changeStr = change !== undefined ? (change >= 0 ? '+' : '') + change.toFixed(2) + '%' : 'N/A';
  const mcap = p[currency + '_market_cap'];
  const mcapStr = mcap ? mcap.toLocaleString('en-US') : 'N/A';
  const vol = p[currency + '_24h_vol'];
  const volStr = vol ? vol.toLocaleString('en-US') : 'N/A';

  let result = coin.charAt(0).toUpperCase() + coin.slice(1) + '\n';
  result += '  Price: ' + p[currency].toLocaleString('en-US', {minimumFractionDigits: 2, maximumFractionDigits: 8}) + ' ' + cur + '\n';
  result += '  24h Change: ' + changeStr + '\n';
  result += '  Market Cap: ' + mcapStr + ' ' + cur + '\n';
  result += '  24h Volume: ' + volStr + ' ' + cur;
  return [{ json: { result } }];

} catch (err) {
  if (err.message && err.message.includes('429')) {
    return [{ json: { error: 'Rate limit exceeded (CoinGecko free: 30 calls/min). Please try again in a moment.' } }];
  }
  return [{ json: { error: 'Failed to fetch crypto price: ' + err.message } }];
}
